# Math utilities module with classes, functions, and enums

enum OperationType:
    ADD = 1
    SUBTRACT = 2
    MULTIPLY = 3
    POWER = 4

class Calculator:
    base_value: float

    def __init__(self, base: float = 0.0):
        self.base_value = base

    @virtual
    def compute(self, a: float, b: float) -> float:
        return self.base_value + a + b

def calculate_square(n: int) -> int:
    return n * n

def calculate_power(base: float, exp: float) -> float:
    result: float = 1.0
    i: int = 0
    while i < int(exp):
        result = result * base
        i = i + 1
    return result

