# Advanced calculations with inheritance from math_utils
# Tests cross-module inheritance and interface implementation

from math_utils import Calculator, OperationType
from data_structures import Container, Box

class ScientificCalculator(Calculator):
    multiplier: float

    def __init__(self, base: float, mult: float):
        super().__init__(base)
        self.multiplier = mult

    @override
    def compute(self, a: float, b: float) -> float:
        # Get base computation and apply multiplier
        base_result: float = super().compute(a, b)
        return base_result * self.multiplier

def create_calculator_box(base: float) -> Box[Calculator]:
    return Box[Calculator](Calculator(base))
